mapper.select:
SELECT a.name, a.bind_time, a.bind_id, a.diy_id, a.cover, a.diy_page_id FROM ( SELECT d.name, DATE_FORMAT( b.bind_time, '%Y-%m-%d %H:%i:%s' ) AS bind_time, b.id AS bind_id, b.diy_id, d.cover, b.diy_page_id, ROW_NUMBER() over(partition by b.diy_id) AS top FROM lkt_diy_page_bind b LEFT JOIN lkt_diy d ON d.id = b.diy_id WHERE b.diy_page_id = #{id} AND d.is_del = 0
and d.name like concat('%',#{name},'%')
) AS a
where a.top = 1
limit #{pageNo},#{pageSize}
